using namespace std;

int main() {
    // Declare and initialize a 2D array
    int matrix[3][3] = {
        {1, 2, 3},  // First row
        {4, 5, 6},  // Second row
        {7, 8, 9}   // Third row
    };

    // Iterating over the 2D array using nested loops
    cout << "Matrix elements:" << endl;
    for (int i = 0; i < 3; i++) {  // Outer loop for rows
        for (int j = 0; j < 3; j++) {  // Inner loop for columns
            cout << matrix[i][j] << " ";  // Access and print each element
        }
        cout << endl;  // Print a new line after each row
    }

    return 0;
}
```

**Expected Output:**

```default
Matrix elements:
1 2 3 
4 5 6 
7 8 9 
```

